import yaml
agents = yaml.safe_load(open('contracts/agent-tools.yaml'))
catalog = yaml.safe_load(open('contracts/event-catalog.yaml'))
catalog_types = {k for k, v in catalog.items() if isinstance(v, dict) and 'emitter' in v}
missing = []
for aid, a in agents.items():
  if not isinstance(a, dict) or 'emit_events' not in a:
    continue
  for evt in a.get('emit_events', []):
    if evt not in catalog_types:
      missing.append(f'{aid}: {evt}')
assert len(missing) == 0, f'Emit events missing from catalog: {missing}'
print(f'All emit_events have catalog entries ({len(catalog_types)} events checked)')
"

python3 -c "
import yaml
agents = yaml.safe_load(open('contracts/agent-tools.yaml'))
catalog = yaml.safe_load(open('contracts/event-catalog.yaml'))
catalog_types = {k for k, v in catalog.items() if isinstance(v, dict) and 'emitter' in v}
missing = []
for aid, a in agents.items():
  if not isinstance(a, dict):
    continue
  for sub in a.get('subscriptions', []) + a.get('subscriptions_bootstrap', []):
    if sub not in catalog_types:
      missing.append(f'{aid}: {sub}')
assert len(missing) == 0, f'Subscriptions missing from catalog: {missing}'
print(f'All subscriptions have catalog entries ({len(catalog_types)} events checked)')
"
